
.tab-nav-shell {
  position: relative;
  flex-shrink: 0;
  min-width: 0;
}

.tab-nav {
  position: relative;
  display: flex;
  padding: 4px 8px 3px;
  gap: 2px;
  background: var(--tab-bg);
  border-top: 1px solid var(--line-subtle);
  border-bottom: 1px solid var(--border-color);
  box-shadow: inset 0 1px 0 color-mix(in srgb, var(--gold) 8%, transparent);
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: none;
  overscroll-behavior-x: contain;
  touch-action: pan-x pinch-zoom;

  &::-webkit-scrollbar {
    display: none;
  }

  .tab-btn {
    position: relative;
    flex: 1;
    min-width: 58px;
    min-height: 38px;
    padding: 6px 8px 7px;
    background: transparent;
    border: 1px solid transparent;
    border-radius: 4px;
    color: var(--text-secondary);
    font-size: 12px;
    cursor: pointer;
    transition: all 0.2s;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 4px;
    white-space: nowrap;

    &:hover {
      background: var(--button-bg);
      color: var(--text-accent);
    }

    &.active {
      background: var(--tab-active);
      border-color: transparent;
      color: var(--gold);

      &::after {
        content: '';
        position: absolute;
        right: 22%;
        bottom: 0;
        left: 22%;
        height: 2px;
        background: linear-gradient(90deg, transparent, var(--gold) 18% 82%, transparent);
        box-shadow: 0 0 10px var(--accent-glow);
      }
    }
  }
}

.tab-scroll-control {
  position: absolute;
  z-index: 4;
  top: 50%;
  width: 28px;
  height: 32px;
  display: none;
  place-items: center;
  padding: 0;
  transform: translateY(-50%);
  border: 1px solid var(--line-strong);
  border-radius: 4px;
  color: var(--gold);
  background: color-mix(in srgb, var(--surface-raised) 94%, transparent);
  box-shadow: 0 0 16px var(--stage-shadow);
  cursor: pointer;

  &.is-left { left: 4px; }
  &.is-right { right: 4px; }
}

// 手机端适配
@media screen and (max-width: 480px) {
  .tab-scroll-control { display: grid; }

  .tab-nav {
    padding: 3px 36px;
    gap: 2px;
    justify-content: flex-start;
    scroll-snap-type: x proximity;

    .tab-btn {
      flex: 0 0 auto;
      min-width: auto;
      min-width: 54px;
      padding: 5px 8px;
      font-size: 11px;
      gap: 3px;
      scroll-snap-align: center;

      i {
        font-size: 12px;
      }
    }
  }
}

// 超小屏幕适配
@media screen and (max-width: 360px) {
  .tab-nav {
    padding: 5px 34px;
    gap: 1px;

    .tab-btn {
      padding: 5px 8px;
      font-size: 10px;

      .tab-label {
        display: none;
      }

      i {
        font-size: 14px;
      }
    }
  }
}
