
.world-map-panel {
  border: 1px solid var(--border-color);
  border-radius: 12px;
  background: var(--bg-primary);
  overflow: hidden;
}

.map-heading {
  grid-column: 1 / -1;
  grid-row: 1;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 14px 16px 12px;
  border-bottom: 1px solid var(--border-color);
  background: var(--bg-secondary);
}

.map-title {
  display: flex;
  align-items: center;
  gap: 8px;
  color: var(--text-primary);
  font-family: 'Noto Serif SC', 'STKaiti', 'KaiTi', serif;
  font-size: 16px;
  font-weight: 700;
  letter-spacing: 1px;

  i {
    color: var(--accent-color);
  }
}

.map-subtitle {
  margin-top: 4px;
  color: var(--text-secondary);
  font-size: 11px;
  letter-spacing: 1px;
}

.map-status {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  flex-wrap: wrap;
  gap: 8px;
}

.danger-pill,
.current-pill,
.route-chip,
.route-label,
.detail-current {
  display: inline-flex;
  align-items: center;
  border-radius: 999px;
  white-space: nowrap;
}

.danger-pill {
  padding: 4px 10px;
  color: #fff;
  font-size: 11px;
  font-weight: 700;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
}

.current-pill {
  max-width: 260px;
  padding: 4px 10px;
  overflow: hidden;
  color: var(--text-accent);
  font-size: 11px;
  text-overflow: ellipsis;
  background: var(--bg-secondary);
  border: 1px solid var(--border-color);
}

/* 星图灵脉核心样式 */
.map-stage {
  position: relative;
  isolation: isolate;
  width: 100%;
  min-width: 0;
  min-height: 0;
  height: auto;
  grid-column: 1;
  grid-row: 2;
  overflow: auto;
  background: var(--surface-inset, var(--bg-primary));
  /* 极简的星空/阵法底纹 */
  background-image:
    radial-gradient(circle at 50% 50%, var(--bg-secondary) 0%, transparent 70%),
    linear-gradient(rgba(255, 255, 255, 0.02) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255, 255, 255, 0.02) 1px, transparent 1px);
  background-size:
    100% 100%,
    20px 20px,
    20px 20px;
  box-shadow:
    inset 0 1px rgba(255, 225, 205, 0.05),
    inset 0 -1px rgba(255, 225, 205, 0.05);
  scrollbar-color: var(--line-strong, var(--border-active)) transparent;
  scrollbar-width: thin;
  cursor: grab;
  touch-action: pan-y;
  user-select: none;

  &.dragging,
  &.dragging * { cursor: grabbing !important; }
}

.map-view-fade-enter-active,
.map-view-fade-leave-active {
  transition:
    opacity 0.2s ease,
    filter 0.2s ease;
}

.map-view-fade-enter-from,
.map-view-fade-leave-to {
  opacity: 0;
  filter: brightness(0.72);
}

.map-view-switcher {
  position: relative;
  z-index: 2;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 4px;
  min-height: 58px;
  grid-column: 1;
  grid-row: 3;
  padding: 9px 12px;
  border-top: 1px solid var(--border-color);
  border-bottom: 1px solid var(--border-color);
  background: color-mix(in srgb, var(--bg-secondary) 88%, transparent);
}

.map-zoom-controls {
  position: absolute;
  right: 12px;
  display: flex;
  align-items: center;
  gap: 4px;

  button {
    min-width: 34px;
    height: 34px;
    padding: 0 9px;
    border: 1px solid var(--border-color);
    border-radius: 6px;
    color: var(--text-secondary);
    background: var(--bg-primary);
    cursor: pointer;

    &:hover:not(:disabled) { border-color: var(--border-active); color: var(--text-accent); }
    &:disabled { opacity: 0.35; cursor: not-allowed; }
  }

  .map-zoom-value {
    min-width: 58px;
    color: var(--text-accent);
    font-variant-numeric: tabular-nums;
  }
}

.map-view-arrow,
.map-view-current {
  height: 36px;
  color: var(--text-secondary);
  border: 1px solid var(--border-color);
  border-radius: 7px;
  background: var(--button-bg);
  transition:
    color 0.18s ease,
    border-color 0.18s ease,
    background 0.18s ease,
    transform 0.18s ease;
  cursor: pointer;

  &:hover {
    color: var(--text-primary);
    border-color: var(--border-active);
    background: var(--button-hover);
  }

  &:active {
    transform: translateY(1px);
  }

  &:focus-visible {
    outline: 2px solid var(--accent-color);
    outline-offset: 2px;
  }
}

.map-view-arrow {
  display: inline-grid;
  place-items: center;
  width: 36px;
  padding: 0;
  font-size: 12px;
}

.map-view-current {
  display: inline-grid;
  grid-template-columns: 16px minmax(68px, auto) 28px;
  align-items: center;
  gap: 7px;
  min-width: 154px;
  padding: 0 11px;
  color: var(--text-primary);
  font-size: 12px;
  font-weight: 700;

  i {
    color: var(--accent-color);
  }

  span {
    white-space: nowrap;
  }

  small {
    color: var(--text-secondary);
    font-size: 10px;
    font-weight: 500;
    text-align: right;
  }
}

.map-canvas {
  display: block;
  width: 100%;
  height: 100%;
  aspect-ratio: 420 / 300;
}

/* 大陆板块轮廓 */
.continent-path {
  fill: var(--area-fill, var(--accent-color));
  fill-opacity: 0.03;
  stroke: var(--area-stroke, var(--accent-color));
  stroke-width: 0.25;
  stroke-dasharray: 2.2 2.4;
  opacity: 0.32;
  transition: all 0.5s cubic-bezier(0.4, 0, 0.2, 1);
  cursor: pointer;

  &.kind-sea {
    fill-opacity: 0.008;
    stroke-width: 0.15;
    stroke-dasharray: 3 3.2;
  }

  &.kind-core {
    fill-opacity: 0.06;
    stroke-width: 0.35;
    stroke-dasharray: 2.6 2.2;
  }

  &.kind-abyss {
    fill-opacity: 0.025;
    stroke-width: 0.2;
    stroke-dasharray: 1.6 2;
  }

  &:hover {
    fill-opacity: 0.1;
    stroke-width: 0.4;
    opacity: 0.8;
    filter: url(#hover-glow);
  }

  &.is-selected {
    fill-opacity: 0.13;
    stroke-width: 0.6;
    stroke-dasharray: 4 2;
    opacity: 1;
    filter: url(#active-glow);
  }

  &.is-current {
    fill-opacity: 0.18;
    stroke-width: 0.8;
    stroke-dasharray: 5 2;
    opacity: 1;
    filter: url(#active-glow);
  }

  &.is-current.is-selected {
    fill-opacity: 0.25;
    stroke-width: 1;
  }
}

/* 境界划分 */
.realm-dividers {
  pointer-events: none;

  .divider-line {
    stroke: var(--text-secondary);
    stroke-width: 0.2;
    stroke-dasharray: 2 4;
    opacity: 0.3;
  }

  .divider-text {
    fill: var(--text-secondary);
    font-size: 4.8px;
    font-weight: 700;
    letter-spacing: 2px;
    font-family: 'Noto Serif SC', serif;
    opacity: 0.4;
  }
}

/* 灵脉连线 */
.vein-base {
  fill: none;
  stroke: var(--text-secondary);
  stroke-width: 0.3;
  opacity: 0.08;
  stroke-linecap: round;
}

.vein-flow {
  fill: none;
  stroke: var(--accent-color);
  stroke-width: 0.4;
  stroke-linecap: round;
  stroke-dasharray: 2 4;
  opacity: 0.14;
  animation: vein-flow-anim 4s linear infinite;

  &.vein-active {
    stroke-width: 0.6;
    opacity: 0.62;
    stroke-dasharray: 3 3;
    animation: vein-flow-anim 2s linear infinite;
  }
}

@keyframes vein-flow-anim {
  to {
    stroke-dashoffset: -12;
  }
}

/* 阵眼节点 */
.node-group {
  cursor: pointer;
  outline: none;

  &:hover {
    .node-core {
      fill: var(--accent-color);
      transform: scale(1.2);
    }
    .node-ring {
      stroke: var(--accent-color);
      opacity: 1;
      transform: scale(1.4);
    }
    .node-label {
      fill: var(--accent-color);
    }
  }

  &.is-selected {
    .node-core {
      fill: var(--accent-color);
      transform: scale(1.2);
    }
    .node-ring {
      stroke: var(--accent-color);
      opacity: 1;
      transform: scale(1.4);
    }
    .node-label {
      fill: var(--text-primary);
      font-weight: 900;
    }
  }

  &.is-current {
    .node-core {
      fill: var(--bg-primary);
      stroke: var(--accent-color);
      stroke-width: 0.5;
      transform: scale(1.2);
    }
    .node-label {
      fill: var(--accent-color);
      font-weight: 900;
      font-size: 3.45px;
    }
  }

  &.is-current.is-selected {
    .node-core {
      fill: var(--accent-color);
      stroke: var(--bg-primary);
      stroke-width: 0.5;
      transform: scale(1.4);
    }
    .node-ring {
      stroke: var(--accent-color);
      opacity: 1;
      transform: scale(1.6);
    }
  }
}

.node-core {
  fill: var(--text-secondary);
  transition: all 0.3s ease;
}

.node-ring {
  fill: none;
  stroke: var(--text-secondary);
  stroke-width: 0.2;
  opacity: 0.5;
  transition: all 0.3s ease;
}

.selected-glow {
  fill: var(--accent-color);
  opacity: 0.2;
  animation: pulse-glow 2s ease-in-out infinite alternate;
}

@keyframes pulse-glow {
  from {
    transform: scale(0.8);
    opacity: 0.1;
  }
  to {
    transform: scale(1.2);
    opacity: 0.3;
  }
}

/* 当前位置涟漪动画 */
.current-ripples {
  pointer-events: none;
}

.ripple {
  fill: none;
  stroke: var(--accent-color);
  stroke-width: 0.4;
  opacity: 0;
  animation: ripple-anim 3s cubic-bezier(0.1, 0.8, 0.3, 1) infinite;

  &.r2 {
    animation-delay: 1.5s;
  }
}

@keyframes ripple-anim {
  0% {
    transform: scale(0.3);
    opacity: 0.8;
    stroke-width: 0.6;
  }
  100% {
    transform: scale(2);
    opacity: 0;
    stroke-width: 0.1;
  }
}

/* 地名标签 */
.node-label {
  fill: var(--text-primary);
  font-size: 3.15px;
  font-weight: 700;
  letter-spacing: 0.2px;
  font-family: 'Noto Serif SC', 'STKaiti', serif;
  /* 使用 paint-order 描边，保证文字在复杂背景下清晰可读 */
  paint-order: stroke;
  stroke: var(--bg-primary);
  stroke-width: 0.45;
  stroke-linejoin: round;
  transition: all 0.3s ease;
  pointer-events: none;
}

.world-map-panel {
  border: 1px solid var(--border-color);
  border-radius: 12px;
  background: var(--bg-primary);
  overflow: hidden;
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(280px, 340px);
  grid-template-rows: auto minmax(0, 1fr) auto;
  height: 100%;
  min-height: 0;
}

.map-detail {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  align-content: start;
  gap: 16px;
  padding: 16px;
  border-top: 1px solid var(--border-color);
  background: var(--bg-secondary);
  min-height: 0;
  overflow-y: auto;
  grid-column: 2;
  grid-row: 2;
  border-top: 0;
  border-left: 1px solid var(--border-color);
}

.detail-kicker {
  color: var(--text-secondary);
  font-size: 11px;
  letter-spacing: 1px;
}

.detail-title {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-top: 6px;
  color: var(--text-primary);
  font-family: 'Noto Serif SC', 'STKaiti', 'KaiTi', serif;
  font-size: 18px;
  font-weight: 800;
  letter-spacing: 1px;
}

.detail-current {
  padding: 3px 8px;
  color: var(--text-accent);
  background: var(--bg-primary);
  border: 1px solid var(--accent-color);
  border-radius: 12px;
  font-size: 10px;
  font-weight: 700;
}

.detail-summary {
  margin-top: 8px;
  color: var(--text-secondary);
  font-size: 13px;
  line-height: 1.7;
}

.detail-grid {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.detail-line {
  display: grid;
  grid-template-columns: 42px minmax(0, 1fr);
  gap: 8px;
  align-items: baseline;
  font-size: 12px;

  span {
    color: var(--accent-color);
    opacity: 0.9;
  }

  strong {
    color: var(--text-primary);
    font-size: 13px;
    font-weight: 500;
    line-height: 1.5;
  }
}

.route-strip {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 8px;
  padding: 0 16px 16px;
  background: var(--bg-secondary);
  grid-column: 2;
  grid-row: 3;
  align-content: center;
  padding: 9px 12px;
  border-top: 1px solid var(--border-color);
}

.route-label {
  color: var(--text-secondary);
  font-size: 11px;
  letter-spacing: 1px;
}

.route-chip {
  padding: 4px 10px;
  color: var(--text-primary);
  background: var(--bg-primary);
  border: 1px solid var(--border-color);
  border-radius: 12px;
  font-size: 11px;
  transition: all 0.2s ease;

  &:hover {
    border-color: var(--accent-color);
    color: var(--text-accent);
  }
}

.expanded-map-canvas {
  display: block;
  max-width: none;
  max-height: none;
  flex: 0 0 auto;
  background:
    radial-gradient(circle at 50% 47%, rgba(255, 198, 120, 0.08), transparent 48%),
    linear-gradient(180deg, rgba(45, 14, 18, 0.12), rgba(20, 6, 9, 0.24));
}

.expanded-map-bg {
  fill: url(#expandedWorldGlow);
}

.expanded-map-grid {
  fill: url(#expandedMapGrid);
  opacity: 0.55;
}

.painted-map-bg {
  opacity: 0.97;
  filter: saturate(0.94) contrast(1.02) brightness(0.98);
}

.map-canvas-overview .painted-map-bg {
  filter: saturate(0.94) contrast(1.02) brightness(0.94);
}

.map-canvas-earth .painted-map-bg {
  filter: saturate(0.96) contrast(1.02) brightness(0.96);
}

.map-canvas-underworld .painted-map-bg {
  filter: saturate(0.92) contrast(1.04) brightness(0.95);
}

.painted-map-tone {
  fill: url(#expandedMapTone);
  pointer-events: none;
  mix-blend-mode: color;
}

.painted-map-vignette {
  fill: url(#expandedMapVignette);
  pointer-events: none;
}

.expanded-layer {
  stroke-width: 0.35;
  stroke-dasharray: 5 4;
  opacity: 0.42;
}

.expanded-layer-sky {
  fill: rgba(114, 154, 202, 0.08);
  stroke: rgba(169, 213, 255, 0.22);
}

.expanded-layer-earth {
  fill: url(#expandedEarthMass);
  stroke: rgba(239, 198, 151, 0.34);
  stroke-width: 0.55;
  opacity: 0.78;
}

.expanded-layer-abyss {
  fill: url(#expandedAbyssFade);
  stroke: rgba(184, 129, 232, 0.22);
}

.expanded-layer-labels {
  pointer-events: none;

  text {
    fill: rgba(255, 224, 205, 0.52);
    font-family: 'Noto Serif SC', 'STKaiti', serif;
    font-size: 6.5px;
    font-weight: 900;
    letter-spacing: 2px;
    paint-order: stroke;
    stroke: rgba(30, 9, 12, 0.64);
    stroke-width: 0.7;
  }
}

.expanded-sea-labels {
  pointer-events: none;

  text {
    fill: rgba(169, 214, 221, 0.68);
    font-family: 'Noto Serif SC', 'STKaiti', 'KaiTi', serif;
    font-size: 4.4px;
    font-weight: 700;
    letter-spacing: 0.7px;
    text-anchor: middle;
    paint-order: stroke;
    stroke: rgba(17, 12, 16, 0.86);
    stroke-width: 0.72;
    stroke-linejoin: round;
  }
}

.expanded-route {
  fill: none;
  stroke-width: 0.42;
  stroke-linecap: round;
  stroke-dasharray: 2.2 3.4;
  opacity: 0.08;
  transition:
    opacity 0.22s ease,
    stroke-width 0.22s ease;

  &.current {
    stroke-width: 0.72;
    opacity: 0.68;
    stroke-dasharray: 4 2.4;
  }
}

.expanded-route-mortal {
  stroke: rgba(255, 218, 133, 0.58);
}

.expanded-route-sea {
  stroke: rgba(105, 219, 226, 0.58);
}

.expanded-route-celestial {
  stroke: rgba(174, 219, 255, 0.58);
}

.expanded-route-abyss {
  stroke: rgba(206, 129, 242, 0.58);
}

.expanded-area {
  cursor: pointer;
  outline: none;
}

.expanded-area-shape {
  fill: var(--area-fill, rgba(255, 214, 160, 0.16));
  stroke: var(--area-stroke, rgba(255, 223, 198, 0.54));
  stroke-width: 0.42;
  stroke-dasharray: 2.4 2.8;
  stroke-linejoin: round;
  fill-rule: evenodd;
  opacity: 0.98;
  transition:
    fill 0.2s ease,
    stroke 0.2s ease,
    stroke-width 0.2s ease,
    opacity 0.2s ease,
    filter 0.2s ease;
}

.expanded-kind-core .expanded-area-shape {
  fill: var(--area-fill, rgba(230, 190, 88, 0.34));
  stroke: var(--area-stroke, rgba(255, 224, 135, 0.72));
}

.expanded-kind-land .expanded-area-shape {
  fill: var(--area-fill, rgba(195, 160, 110, 0.28));
  stroke: var(--area-stroke, rgba(240, 206, 168, 0.62));
}

.expanded-kind-sea .expanded-area-shape {
  fill: var(--area-fill, rgba(64, 157, 172, 0.2));
  stroke: var(--area-stroke, rgba(118, 222, 230, 0.56));
}

.expanded-kind-border .expanded-area-shape {
  fill: var(--area-fill, rgba(230, 196, 126, 0.28));
  stroke: var(--area-stroke, rgba(250, 218, 158, 0.68));
  stroke-width: 0.62;
}

.expanded-kind-celestial .expanded-area-shape {
  fill: var(--area-fill, rgba(147, 181, 226, 0.18));
  stroke: var(--area-stroke, rgba(186, 224, 255, 0.58));
}

.expanded-kind-abyss .expanded-area-shape {
  fill: var(--area-fill, rgba(96, 67, 122, 0.22));
  stroke: var(--area-stroke, rgba(190, 153, 235, 0.56));
}

.expanded-area:hover .expanded-area-shape,
.expanded-area.selected .expanded-area-shape {
  fill: var(--area-fill, rgba(255, 210, 160, 0.28));
  stroke: rgba(247, 217, 178, 0.9);
  stroke-width: 0.68;
  filter: url(#expandedSoftGlow);
}

.expanded-area.current .expanded-area-shape {
  fill: var(--area-fill, rgba(255, 190, 190, 0.32));
  stroke: rgba(255, 180, 150, 0.96);
  stroke-width: 0.76;
  filter: url(#expandedSoftGlow);
}

.expanded-earth-boundaries {
  pointer-events: none;
}

.expanded-earth-boundary {
  fill: none;
  stroke: rgba(255, 229, 196, 0.28);
  stroke-width: 0.34;
  stroke-dasharray: 1.8 2.4;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.expanded-terrain {
  pointer-events: none;
  opacity: 0.58;
}

.terrain {
  fill: none;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.terrain.mountain {
  stroke: rgba(235, 219, 190, 0.5);
  stroke-width: 0.8;
}

.terrain.river {
  stroke: rgba(130, 210, 220, 0.45);
  stroke-width: 0.6;
}

.terrain.ice {
  stroke: rgba(215, 241, 255, 0.45);
  stroke-width: 0.55;
}

.terrain.forest {
  stroke: rgba(159, 223, 142, 0.48);
  stroke-width: 0.75;
}

.terrain.volcano {
  stroke: rgba(255, 147, 98, 0.55);
  stroke-width: 0.75;
}

.terrain.storm {
  stroke: rgba(180, 145, 255, 0.58);
  stroke-width: 0.75;
}

.terrain.vortex {
  stroke: rgba(150, 181, 255, 0.62);
  stroke-width: 0.62;
}

.terrain.fissure {
  stroke: rgba(190, 111, 228, 0.46);
  stroke-width: 0.55;
  stroke-dasharray: 3 2;
}

.expanded-label {
  cursor: pointer;
  outline: none;

  circle {
    fill: rgba(235, 177, 165, 0.96);
    stroke: rgba(255, 237, 222, 0.76);
    stroke-width: 0.32;
    filter: drop-shadow(0 0 1.2px rgba(27, 7, 10, 0.92));
  }

  text {
    fill: rgba(255, 241, 232, 0.98);
    font-family: 'Noto Serif SC', 'STKaiti', 'KaiTi', serif;
    font-size: 5.2px;
    font-weight: 800;
    letter-spacing: 0;
    paint-order: stroke;
    stroke: rgba(30, 8, 11, 0.9);
    stroke-width: 0.96;
    stroke-linejoin: round;
    filter: drop-shadow(0 0.6px 0.45px rgba(0, 0, 0, 0.62));
  }

  &.selected text,
  &.current text {
    fill: rgba(255, 213, 205, 1);
    font-weight: 900;
  }

  &.current circle {
    fill: rgba(255, 202, 195, 1);
  }
}

.expanded-current-marker {
  pointer-events: none;
  filter: url(#expandedSoftGlow);

  text {
    fill: rgba(255, 232, 219, 0.98);
    font-size: 3.6px;
    font-weight: 800;
    letter-spacing: 0;
  }
}

.expanded-current-tag {
  fill: rgba(44, 13, 17, 0.88);
  stroke: rgba(255, 186, 157, 0.82);
  stroke-width: 0.42;
}

.expanded-current-pointer {
  fill: none;
  stroke: rgba(255, 190, 163, 0.9);
  stroke-width: 0.45;
  stroke-linecap: round;
}

.expanded-current-ring {
  fill: rgba(255, 176, 148, 0.08);
  stroke: rgba(255, 195, 169, 0.92);
  stroke-width: 0.62;
  stroke-dasharray: 1.6 1.2;
  animation: expanded-current-pulse 2.4s ease-in-out infinite;
}

.expanded-current-core {
  fill: rgba(255, 190, 163, 1);
  stroke: rgba(70, 14, 18, 0.7);
  stroke-width: 0.28;
}

.has-painted-map {
  .expanded-map-bg {
    opacity: 0.68;
  }

  .expanded-map-grid {
    opacity: 0.26;
    mix-blend-mode: soft-light;
  }

  .expanded-layer {
    opacity: 0.16;
  }

  .expanded-layer-earth {
    fill: rgba(12, 6, 6, 0.08);
    stroke: rgba(140, 225, 232, 0.48);
    stroke-width: 0.45;
    opacity: 0.54;
  }

  .expanded-layer-sky,
  .expanded-layer-abyss {
    fill: transparent;
  }

  .expanded-area-shape {
    fill-opacity: 0.035;
    stroke-opacity: 0.48;
    stroke-width: 0.42;
    mix-blend-mode: normal;
  }

  .expanded-kind-celestial .expanded-area-shape,
  .expanded-kind-abyss .expanded-area-shape {
    fill-opacity: 0.06;
    stroke-opacity: 0.58;
  }

  .expanded-kind-sea .expanded-area-shape {
    fill-opacity: 0.02;
    stroke-opacity: 0.38;
  }

  .expanded-area:hover .expanded-area-shape,
  .expanded-area.selected .expanded-area-shape {
    fill-opacity: 0.13;
    stroke-opacity: 0.94;
    stroke-width: 0.68;
  }

  .expanded-area.current .expanded-area-shape {
    fill-opacity: 0.12;
    stroke-opacity: 0.96;
    stroke-width: 0.76;
  }

  .expanded-earth-boundary {
    stroke: rgba(255, 232, 204, 0.38);
    stroke-width: 0.3;
    stroke-opacity: 0.54;
  }

  .expanded-route {
    opacity: 0.07;
  }

  .expanded-route-abyss {
    stroke: rgba(201, 150, 235, 0.72);
    opacity: 0.14;
    stroke-width: 0.54;
    stroke-dasharray: 3.4 3;
  }

  .expanded-route.current {
    opacity: 0.7;
    filter: drop-shadow(0 0 1.5px rgba(255, 205, 166, 0.38));
  }

  .expanded-terrain {
    display: none;
  }

  .expanded-label text {
    stroke: rgba(18, 5, 7, 0.94);
    stroke-width: 1;
  }
}

@keyframes expanded-current-pulse {
  0%,
  100% {
    opacity: 0.84;
    transform: scale(0.96);
  }

  50% {
    opacity: 1;
    transform: scale(1.08);
  }
}

@media screen and (max-width: 680px) {
  .world-map-panel {
    display: flex;
    flex-direction: column;
    overflow-y: auto;
  }

  .map-heading,
  .map-detail {
    grid-template-columns: 1fr;
  }

  .map-heading {
    align-items: flex-start;
    flex-direction: column;
  }

  .map-status {
    justify-content: flex-start;
  }

  .map-stage {
    width: 100%;
    height: auto;
    min-height: auto;
    aspect-ratio: 420 / 300;
    flex: 0 0 auto;
    overflow: auto;
  }

  .map-view-switcher { justify-content: flex-start; }
  .map-zoom-controls { position: static; margin-left: auto; }
  .map-zoom-controls button { min-width: 30px; height: 32px; padding: 0 7px; }
  .map-zoom-controls .map-zoom-value { min-width: 48px; }

  .map-detail {
    overflow: visible;
    border-top: 1px solid var(--border-color);
    border-left: 0;
  }

  .label-text {
    font-size: 3.5px;
  }

  .label-border .label-text,
  .label-sea .label-text,
  .label-celestial .label-text,
  .label-abyss .label-text {
    font-size: 3px;
  }

  .current-location-text {
    font-size: 3.35px;
  }
}

@media screen and (max-width: 420px) {
  .map-stage {
    height: auto;
  }

  .map-detail {
    padding: 10px 12px 12px;
  }
}
