
.map-panel {
  padding: 20px;
  background: transparent;
  border: 0;
  border-radius: 0;
  color: var(--text-primary);

  .location-brief {
    display: flex;
    flex-direction: column;
    gap: 16px;
    margin: 24px 0;
    padding: 20px 0;
    background: transparent;
    border-top: 1px solid var(--line-subtle);
    border-bottom: 1px solid var(--line-subtle);
    border-radius: 0;
  }

  .brief-header {
    text-align: center;
  }

  .brief-label {
    font-size: 12px;
    color: var(--text-secondary);
    letter-spacing: 2px;
    margin-bottom: 8px;
  }

  .brief-title {
    font-size: 26px;
    font-weight: bold;
    color: var(--text-accent);
    margin-bottom: 6px;
    letter-spacing: 0;
    font-family: 'Songti SC', 'STSong', serif;
  }

  .brief-domain {
    font-size: 14px;
    color: var(--accent-color);
  }

  .brief-desc {
    font-size: 14px;
    color: var(--text-secondary);
    line-height: 1.8;
    text-align: center;
    padding: 16px 24px;
    background: var(--surface-inset);
    border: 1px solid var(--line-subtle);
    border-radius: 6px;

    .quote-icon {
      color: var(--border-color);
      font-size: 12px;
      margin: 0 6px;
      vertical-align: super;
    }
  }

  .brief-routes {
    margin-top: 8px;
    
    .routes-title {
      font-size: 13px;
      color: var(--text-secondary);
      margin-bottom: 12px;
      display: flex;
      align-items: center;
      gap: 6px;
      justify-content: center;

      i { color: var(--accent-color); }
    }
  }

  .connections-list {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    justify-content: center;

    .connection-item {
      padding: 6px 16px;
      background: var(--bg-primary);
      border: 1px solid var(--border-color);
      border-radius: 20px;
      font-size: 13px;
      color: var(--text-primary);
      transition: all 0.3s ease;
      display: flex;
      align-items: center;
      gap: 6px;

      i {
        font-size: 11px;
        color: var(--accent-color);
        opacity: 0.8;
      }

      &:hover {
        transform: translateY(-2px);
        border-color: var(--accent-color);
        color: var(--text-accent);
      }
    }
  }

  .section-title {
    font-size: 18px;
    font-weight: bold;
    color: var(--text-primary);
    margin-bottom: 16px;
    display: flex;
    align-items: center;
    gap: 10px;
    padding-bottom: 8px;
    border-bottom: 1px solid var(--border-color);

    i {
      color: var(--accent-color);
      font-size: 16px;
    }
  }

  .tasks-section {
    margin-bottom: 24px;

    .tasks-list {
      display: flex;
      flex-direction: column;
      gap: 12px;
    }

    .task-item {
      padding: 16px;
      background: var(--bg-secondary);
      border: 1px solid var(--border-color);
      border-radius: 10px;
      position: relative;
      overflow: hidden;
      transition: transform 0.2s;

      &:hover {
        border-color: var(--accent-color);
      }

      &::before {
        content: '';
        position: absolute;
        left: 0; top: 0; bottom: 0; width: 3px;
      }

      &.task-进行中::before { background: var(--accent-color); }
      &.task-已完成::before { background: #4ade80; }
      &.task-已失败::before { background: #f87171; }

      .task-header {
        display: flex;
        justify-content: space-between;
        align-items: center;
        margin-bottom: 10px;

        .task-name {
          font-size: 15px;
          font-weight: bold;
          color: var(--text-primary);
        }

        .task-type {
          font-size: 11px;
          padding: 2px 10px;
          border-radius: 12px;
          border: 1px solid currentColor;
          background: var(--bg-primary);

          &.type-主线 { color: #fca5a5; }
          &.type-支线 { color: #93c5fd; }
          &.type-每日 { color: #86efac; }
          &.type-临危受命 { color: #fdba74; }
        }
      }

      .task-target {
        font-size: 13px;
        color: var(--text-secondary);
        line-height: 1.6;
      }

      .task-status {
        position: absolute;
        right: 16px;
        bottom: 16px;
        font-size: 12px;
        color: var(--text-secondary);
        opacity: 0.8;
      }
    }
  }

  .reputation-section {
    .reputation-list {
      display: flex;
      flex-direction: column;
      gap: 12px;
    }

    .reputation-item {
      padding: 14px 16px;
      background: var(--bg-secondary);
      border: 1px solid var(--border-color);
      border-radius: 10px;

      .reputation-faction {
        font-size: 14px;
        color: var(--text-primary);
        margin-bottom: 10px;
        font-weight: bold;
      }

      .reputation-bar {
        height: 4px;
        background: var(--bg-primary);
        border-radius: 2px;
        overflow: hidden;
        margin-bottom: 10px;

        .reputation-fill {
          height: 100%;
          border-radius: 2px;
        }
      }

      .reputation-info {
        display: flex;
        justify-content: space-between;
        align-items: center;
        font-size: 12px;

        .reputation-value {
          color: var(--text-accent);
          font-family: monospace;
        }

        .reputation-relation {
          color: var(--text-secondary);
        }
      }
    }
  }

  .empty-hint {
    text-align: center;
    padding: 24px;
    color: var(--text-secondary);
    font-style: italic;
    background: var(--bg-secondary);
    border-radius: 8px;
    border: 1px dashed var(--border-color);

    &.compact {
      padding: 8px 16px;
      background: transparent;
      border: none;
    }
  }
}

@media screen and (max-width: 480px) {
  .map-panel {
    padding: 12px;

    .location-brief {
      padding: 16px;
      margin: 16px 0;
    }

    .brief-title { font-size: 22px; }
    .brief-desc { padding: 12px 16px; font-size: 13px; }
    
    .section-title { font-size: 16px; }
    
    .tasks-section .task-item {
      padding: 12px;
      .task-name { font-size: 14px; }
      .task-target { font-size: 12px; }
    }
  }
}
